"use client";

import React, { useEffect, useMemo, useRef, useState } from "react";
import {
  Eye,
  Trash2,
  Check,
  Download,
  X,
  ChevronLeft,
  ChevronRight,
} from "lucide-react";

/* =======================
   TYPES
======================= */
type Row = {
  no: number;
  usulanId?: string;
  esl: string;
  jabatan: string;
  namaPktGolNrpNip: string;
  kondisi: string;
  calonPengisiJabatan: string;
  catatan: string;
  ket: string;
};

type BahanRapat = {
  id: string;
  tanggal: string; // yyyy-mm-dd
  materiRapat: string;
  rows: Row[];
  status: "draft" | "final";
  createdAt: string;
  updatedAt?: string;
};

const STORAGE_KEY_BAHAN_RAPAT = "bnn_bahan_rapat_v1";
const ROWS_PER_PAGE = 5;

/* =======================
   STORAGE
======================= */
function loadBahanRapat(): BahanRapat[] {
  if (typeof window === "undefined") return [];
  try {
    const raw = localStorage.getItem(STORAGE_KEY_BAHAN_RAPAT);
    const data = raw ? (JSON.parse(raw) as BahanRapat[]) : [];
    return Array.isArray(data) ? data : [];
  } catch {
    return [];
  }
}

function saveBahanRapat(list: BahanRapat[]) {
  localStorage.setItem(STORAGE_KEY_BAHAN_RAPAT, JSON.stringify(list));
}

/* =======================
   UTILS
======================= */
function fmtDate(iso: string) {
  if (!iso) return "-";
  const [y, m, d] = iso.split("-");
  if (!y || !m || !d) return iso;
  return `${d}/${m}/${y}`;
}

function chunkRows<T>(arr: T[], size: number) {
  const out: T[][] = [];
  for (let i = 0; i < arr.length; i += size) out.push(arr.slice(i, i + size));
  return out.length ? out : [[]];
}

/** huruf kapital semua (buat judul) */
function toUpperClean(s: string) {
  return String(s ?? "").trim().toUpperCase();
}

/** Judul final: tanpa kurung */
function buildJudul(materiRapat: string) {
  const m = String(materiRapat ?? "").trim();
  if (!m) return "MATERI RAPAT";
  return `MATERI RAPAT ${toUpperClean(m)}`;
}

/* =======================
   PAGE
======================= */
export default function DaftarBahanRapatPage() {
  const [items, setItems] = useState<BahanRapat[]>([]);
  const [openId, setOpenId] = useState<string | null>(null);

  // preview paging (slide)
  const [pageIndex, setPageIndex] = useState(0);
  const [exporting, setExporting] = useState(false);

  // refs untuk render halaman pdf (hidden)
  const pageRefs = useRef<Array<HTMLDivElement | null>>([]);

  useEffect(() => {
    setItems(loadBahanRapat());
  }, []);

  const sorted = useMemo(() => {
    return [...items].sort((a, b) =>
      (b.createdAt || "").localeCompare(a.createdAt || "")
    );
  }, [items]);

  const active = useMemo(() => {
    if (!openId) return null;
    return items.find((x) => x.id === openId) ?? null;
  }, [openId, items]);

  const pages = useMemo(() => {
    if (!active) return [];
    return chunkRows(active.rows || [], ROWS_PER_PAGE);
  }, [active]);

  useEffect(() => {
    setPageIndex(0);
  }, [openId]);

  /** ✅ FIX TS: status tetap literal union */
  function toggleFinal(id: string) {
    const next: BahanRapat[] = items.map((x) => {
      if (x.id !== id) return x;
      const toFinal = x.status !== "final";
      return {
        ...x,
        status: (toFinal ? "final" : "draft") as BahanRapat["status"],
        updatedAt: new Date().toISOString(),
      };
    });

    setItems(next);
    saveBahanRapat(next);
  }

  function onDelete(id: string) {
    const ok = confirm("Yakin mau hapus bahan rapat ini?");
    if (!ok) return;

    const next = items.filter((x) => x.id !== id);
    setItems(next);
    saveBahanRapat(next);

    if (openId === id) setOpenId(null);
  }

  /* =======================
     AUTO DOWNLOAD PDF
     - Perbaiki issue text kepotong:
       1) line-height + padding lebih aman di komponen kop
       2) html2canvas windowWidth/Height + scrollX/Y
       3) onclone set font-family + smoothing + overflow visible
  ======================= */
  async function onExportPdf() {
    if (!active) return;

    try {
      setExporting(true);

      // pastiin halaman hidden udah ke-render
      await new Promise((r) => setTimeout(r, 120));

      const [{ default: html2canvas }, { jsPDF }] = await Promise.all([
        import("html2canvas"),
        import("jspdf"),
      ]);

      const pdf = new jsPDF({
        orientation: "landscape",
        unit: "mm",
        format: "a4",
      });
      const pageW = 297; // A4 landscape width mm
      const pageH = 210; // A4 landscape height mm

      for (let i = 0; i < pages.length; i++) {
        const el = pageRefs.current[i];
        if (!el) continue;

        const canvas = await html2canvas(el, {
          scale: 2,
          backgroundColor: "#ffffff",
          useCORS: true,
          logging: false,
          scrollX: 0,
          scrollY: 0,
          windowWidth: el.scrollWidth,
          windowHeight: el.scrollHeight,

          onclone: (clonedDoc) => {
            const style = clonedDoc.createElement("style");
            style.innerHTML = `
              html, body { background:#fff !important; }
              body { color:#111 !important; }

              /* penting: hindari teks kepotong & overflow */
              .a4l-pdf-page { overflow: visible !important; }

              /* paksa font stabil + smoothing */
              .a4l-pdf-page, .a4l-pdf-page * {
                font-family: Arial, Helvetica, sans-serif !important;
                -webkit-font-smoothing: antialiased !important;
                text-rendering: geometricPrecision !important;

                background-color: #ffffff !important;
                color: #111111 !important;
                border-color: #000000 !important;
                box-shadow: none !important;
                text-shadow: none !important;
                filter: none !important;
                -webkit-print-color-adjust: exact !important;
                print-color-adjust: exact !important;
              }

              .a4l-pdf-page thead tr { background: #e5e7eb !important; }
            `;
            clonedDoc.head.appendChild(style);
          },
        });

        const img = canvas.toDataURL("image/png");

        if (i > 0) pdf.addPage("a4", "landscape");
        pdf.addImage(img, "PNG", 0, 0, pageW, pageH, undefined, "FAST");
      }

      const fileName = `BahanRapat_${active.tanggal || "tanggal"}_${
        active.id
      }.pdf`;
      pdf.save(fileName);
    } catch (err) {
      console.error(err);
      alert("Gagal download PDF. Lihat console untuk detail error.");
    } finally {
      setExporting(false);
    }
  }

  return (
    <div className="px-2 py-2">
      {/* =======================
          LIST (DAFTAR)
      ======================= */}
      <div className="mx-auto w-full max-w-[1100px] rounded-md bg-white shadow-[0_14px_40px_rgba(0,0,0,0.18)] ring-1 ring-black/5">
        <div className="p-10">
          <div className="flex items-start justify-between gap-6">
            <div className="text-[11px] font-semibold text-zinc-900">
              <div>BADAN NARKOTIKA NASIONAL</div>
              <div>REPUBLIK INDONESIA</div>
              <div className="mt-2 h-[2px] w-[190px] bg-zinc-700/70" />
            </div>

            <div className="flex-1 pt-2 text-center">
              <div className="text-sm font-bold tracking-wide text-zinc-900">
                DAFTAR BAHAN RAPAT
              </div>
            </div>

            <div className="w-[190px]" />
          </div>

          <div className="mt-8 overflow-x-auto">
            <table className="w-full border border-zinc-700 text-[12px] text-zinc-900">
              <thead>
                <tr className="bg-zinc-200/80">
                  <Th className="w-[60px] text-center">NO</Th>
                  <Th className="w-[520px] text-center">NAMA RAPAT</Th>
                  <Th className="w-[160px] text-center">TANGGAL</Th>
                  <Th className="w-[120px] text-center">STATUS</Th>
                  <Th className="w-[120px] text-center">AKSI</Th>
                </tr>
              </thead>

              <tbody>
                {sorted.length === 0 ? (
                  <tr className="border-t border-zinc-700">
                    <Td colSpan={5} className="py-10 text-center text-zinc-500">
                      Belum ada data bahan rapat. Silakan buat dulu di menu
                      “Buat Bahan Rapat”.
                    </Td>
                  </tr>
                ) : (
                  sorted.map((doc, idx) => {
                    const namaRapat = doc.materiRapat?.trim()
                      ? toUpperClean(doc.materiRapat)
                      : "-";

                    return (
                      <tr key={doc.id} className="border-t border-zinc-700">
                        <Td className="text-center">{idx + 1}.</Td>

                        <Td className="align-top whitespace-pre-wrap font-semibold">
                          {namaRapat}
                        </Td>

                        <Td className="text-center">{fmtDate(doc.tanggal)}</Td>

                        <Td className="text-center">
                          {doc.status === "final" ? (
                            <span className="inline-flex items-center rounded-md bg-emerald-50 px-2 py-1 text-[11px] font-bold text-emerald-700">
                              FINAL
                            </span>
                          ) : (
                            <button
                              type="button"
                              onClick={() => toggleFinal(doc.id)}
                              className="inline-flex items-center justify-center rounded-md border border-emerald-500/40 bg-white px-2 py-1 text-emerald-700 hover:bg-emerald-50"
                              title="Klik untuk ACC (Final)"
                            >
                              <Check size={18} />
                            </button>
                          )}
                        </Td>

                        <Td className="text-center">
                          <div className="flex items-center justify-center gap-2">
                            <button
                              type="button"
                              onClick={() => setOpenId(doc.id)}
                              className="inline-flex h-9 w-9 items-center justify-center rounded-md border border-[#123473]/40 bg-white text-[#123473] shadow-sm hover:bg-[#123473]/5 active:scale-[0.98]"
                              title="Lihat"
                            >
                              <Eye size={18} />
                            </button>

                            <button
                              type="button"
                              onClick={() => onDelete(doc.id)}
                              className="inline-flex h-9 w-9 items-center justify-center rounded-md border border-red-500/40 bg-white text-red-600 shadow-sm hover:bg-red-50 active:scale-[0.98]"
                              title="Hapus"
                            >
                              <Trash2 size={18} />
                            </button>
                          </div>
                        </Td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>

          <div className="mt-10 text-[10px] text-zinc-700">
            <div>Biro SDM Aparatur dan Organisasi</div>
            <div>Sekretariat Utama BNN 2026</div>
          </div>
        </div>
      </div>

      {/* =======================
          MODAL PREVIEW (SLIDE)
      ======================= */}
      {active && (
        <div className="fixed inset-0 z-[9999] bg-black/40 p-4">
          <div className="mx-auto flex h-full w-full max-w-[1400px] flex-col overflow-hidden rounded-lg bg-white shadow-xl ring-1 ring-black/10">
            {/* toolbar */}
            <div className="flex items-center justify-between gap-3 border-b px-5 py-4">
              <div>
                <div className="text-sm font-bold text-zinc-900">
                  Preview A4 Landscape (Slide)
                </div>
                <div className="mt-1 text-xs text-zinc-600">
                  Nama Rapat:{" "}
                  <b className="text-zinc-900">
                    {active.materiRapat?.trim()
                      ? toUpperClean(active.materiRapat)
                      : "-"}
                  </b>{" "}
                  • Tanggal:{" "}
                  <b className="text-zinc-900">{fmtDate(active.tanggal)}</b> •
                  Status:{" "}
                  <b
                    className={
                      active.status === "final"
                        ? "text-emerald-700"
                        : "text-zinc-900"
                    }
                  >
                    {active.status.toUpperCase()}
                  </b>
                </div>
              </div>

              <div className="flex items-center gap-2">
                {active.status !== "final" ? (
                  <button
                    type="button"
                    onClick={() => toggleFinal(active.id)}
                    className="inline-flex items-center gap-2 rounded-md bg-emerald-600 px-3 py-2 text-xs font-semibold text-white hover:brightness-110"
                  >
                    <Check size={16} />
                    ACC (Final)
                  </button>
                ) : null}

                <button
                  type="button"
                  onClick={onExportPdf}
                  disabled={exporting}
                  className="inline-flex items-center gap-2 rounded-md bg-[#123473] px-3 py-2 text-xs font-semibold text-white hover:brightness-110 disabled:opacity-60"
                >
                  <Download size={16} />
                  {exporting ? "Membuat PDF..." : "Download PDF"}
                </button>

                <button
                  type="button"
                  onClick={() => setOpenId(null)}
                  className="inline-flex items-center gap-2 rounded-md border border-zinc-300 bg-white px-3 py-2 text-xs font-semibold text-zinc-700 hover:bg-zinc-50"
                >
                  <X size={16} />
                  Tutup
                </button>
              </div>
            </div>

            {/* slide content */}
            <div className="flex-1 bg-zinc-100 p-6">
              <div className="mx-auto flex max-w-[1200px] items-center justify-between gap-4">
                <button
                  type="button"
                  onClick={() => setPageIndex((p) => Math.max(0, p - 1))}
                  disabled={pageIndex === 0}
                  className="inline-flex items-center gap-2 rounded-md border bg-white px-3 py-2 text-xs font-semibold text-zinc-700 shadow-sm disabled:opacity-50"
                >
                  <ChevronLeft size={16} /> Prev
                </button>

                <div className="text-xs text-zinc-700">
                  Halaman <b>{pageIndex + 1}</b> / {pages.length}
                </div>

                <button
                  type="button"
                  onClick={() =>
                    setPageIndex((p) => Math.min(pages.length - 1, p + 1))
                  }
                  disabled={pageIndex >= pages.length - 1}
                  className="inline-flex items-center gap-2 rounded-md border bg-white px-3 py-2 text-xs font-semibold text-zinc-700 shadow-sm disabled:opacity-50"
                >
                  Next <ChevronRight size={16} />
                </button>
              </div>

              <div className="mt-4 flex justify-center">
                <A4LandscapePageView
                  doc={active}
                  rows={pages[pageIndex] || []}
                  startNo={pageIndex * ROWS_PER_PAGE + 1}
                  pageIndex={pageIndex}
                  totalPages={pages.length}
                />
              </div>
            </div>

            {/* hidden render semua halaman untuk export PDF */}
            <div className="pointer-events-none absolute left-[-99999px] top-0 opacity-0">
              {pages.map((rows, i) => (
                <div
                  key={i}
                  ref={(el) => {
                    pageRefs.current[i] = el;
                  }}
                  className="a4l-pdf-page"
                >
                  <A4LandscapePageInner
                    doc={active}
                    rows={rows}
                    startNo={i * ROWS_PER_PAGE + 1}
                    pageIndex={i}
                    totalPages={pages.length}
                  />
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      <style jsx global>{`
        .a4l-pdf-page {
          width: 297mm;
          height: 210mm;
          background: #fff;
          overflow: visible;
        }
      `}</style>
    </div>
  );
}

/* =======================
   A4 LANDSCAPE VIEW WRAPPER
======================= */
function A4LandscapePageView({
  doc,
  rows,
  startNo,
  pageIndex,
  totalPages,
}: {
  doc: BahanRapat;
  rows: Row[];
  startNo: number;
  pageIndex: number;
  totalPages: number;
}) {
  return (
    <div className="rounded-md border border-zinc-200 bg-white shadow-sm">
      <div className="a4l-preview">
        <A4LandscapePageInner
          doc={doc}
          rows={rows}
          startNo={startNo}
          pageIndex={pageIndex}
          totalPages={totalPages}
        />
      </div>

      <style jsx>{`
        .a4l-preview {
          width: 297mm;
          height: 210mm;
          padding: 8mm;
        }
      `}</style>
    </div>
  );
}

/* =======================
   A4 LANDSCAPE PAGE CONTENT
======================= */
function A4LandscapePageInner({
  doc,
  rows,
  startNo,
  pageIndex,
  totalPages,
}: {
  doc: BahanRapat;
  rows: Row[];
  startNo: number;
  pageIndex: number;
  totalPages: number;
}) {
  const judul = buildJudul(doc.materiRapat);

  return (
    <div
      style={{
        width: "297mm",
        height: "210mm",
        padding: "8mm",
        boxSizing: "border-box",
        fontFamily: "Arial, Helvetica, sans-serif",
      }}
    >
      {/* KOP + JUDUL */}
      <div className="flex items-start justify-between">
        {/* ✅ dibuat lebih aman biar html2canvas gak clip text */}
        <div
          style={{
            color: "#111",
            fontSize: 12,
            fontWeight: 700,
            lineHeight: 1.35,
            paddingTop: 1,
            paddingBottom: 2,
            display: "block",
            transform: "translateZ(0)",
          }}
        >
          <div style={{ paddingBottom: 1 }}>BADAN NARKOTIKA NASIONAL</div>
          <div style={{ paddingBottom: 2 }}>REPUBLIK INDONESIA</div>
          <div
            style={{
              height: 2,
              width: 220,
              background: "#111",
              marginTop: 2,
            }}
          />
        </div>

        <div className="flex-1 text-center">
          <div
            style={{
              color: "#111",
              fontSize: 13,
              fontWeight: 800,
              lineHeight: 1.25,
              whiteSpace: "pre-wrap",
              transform: "translateZ(0)",
            }}
          >
            {judul}
          </div>

          <div
            style={{
              marginTop: 4,
              color: "#111",
              fontSize: 12,
              fontWeight: 700,
              lineHeight: 1.25,
            }}
          >
            Tanggal {fmtDate(doc.tanggal)}
          </div>
        </div>

        <div style={{ width: 220 }} />
      </div>

      {/* TABLE */}
      <div className="mt-4">
        <table
          className="w-full"
          style={{
            borderCollapse: "collapse",
            fontSize: 12,
            color: "#111",
          }}
        >
          <thead>
            <tr style={{ background: "#e5e7eb" }}>
              <ThPDF w={32}>NO</ThPDF>
              <ThPDF w={55}>ESL</ThPDF>
              <ThPDF w={260}>JABATAN</ThPDF>
              <ThPDF w={260}>
                NAMA/PKT/GOL <br /> NRP/NIP
              </ThPDF>
              <ThPDF w={150}>KONDISI</ThPDF>
              <ThPDF w={280}>CALON PENGISI JABATAN</ThPDF>
              <ThPDF w={180}>CATATAN</ThPDF>
              <ThPDF w={170}>KET</ThPDF>
            </tr>
          </thead>

          <tbody>
            {rows.length ? (
              rows.map((r, i) => (
                <tr key={`${pageIndex}-${i}`}>
                  <TdPDF center>{startNo + i}.</TdPDF>
                  <TdPDF>{r.esl || "-"}</TdPDF>
                  <TdPDF>{r.jabatan || "-"}</TdPDF>
                  <TdPDF>{r.namaPktGolNrpNip || "-"}</TdPDF>
                  <TdPDF>{r.kondisi || "-"}</TdPDF>
                  <TdPDF>{r.calonPengisiJabatan || "-"}</TdPDF>
                  <TdPDF>{r.catatan || "-"}</TdPDF>
                  <TdPDF>{r.ket || "-"}</TdPDF>
                </tr>
              ))
            ) : (
              <tr>
                <td
                  colSpan={8}
                  style={{
                    border: "1px solid #000",
                    padding: 12,
                    textAlign: "center",
                    color: "#666",
                  }}
                >
                  Tidak ada baris data.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* footer kiri */}
      <div className="mt-3" style={{ fontSize: 11, color: "#111" }}>
        <i>Biro SDM Aparatur dan Organisasi Sekretariat Utama BNN 2026</i>
      </div>

      {/* paraf */}
      <div
        className="mt-6"
        style={{ borderTop: "1px solid #555", paddingTop: 6 }}
      >
        <div style={{ fontSize: 11, color: "#555" }}>PARAF:</div>
        <div
          className="mt-2 grid grid-cols-5 gap-2"
          style={{ fontSize: 11, color: "#111" }}
        >
          <ParafBox title="1. SESTAMA" />
          <ParafBox title="2. DEPUTI PENCEGAHAN" />
          <ParafBox title="3. PLT. IRTAMA" />
          <ParafBox title="4. PLT. IRWASRIKSUS" />
          <ParafBox title="5. PLT. KARO SDMA & ORG" />
        </div>
      </div>

      <div className="mt-2 text-right" style={{ fontSize: 11, color: "#666" }}>
        Halaman {pageIndex + 1} / {totalPages}
      </div>
    </div>
  );
}

/* =======================
   PDF TABLE CELLS
======================= */
function ThPDF({ children, w }: { children: React.ReactNode; w: number }) {
  return (
    <th
      style={{
        border: "1px solid #000",
        padding: "6px 6px",
        textAlign: "center",
        width: w,
        fontWeight: 700,
      }}
    >
      {children}
    </th>
  );
}

function TdPDF({
  children,
  center,
}: {
  children: React.ReactNode;
  center?: boolean;
}) {
  return (
    <td
      style={{
        border: "1px solid #000",
        padding: "6px 6px",
        verticalAlign: "top",
        whiteSpace: "pre-wrap",
        textAlign: center ? "center" : "left",
      }}
    >
      {children}
    </td>
  );
}

function ParafBox({ title }: { title: string }) {
  return (
    <div style={{ border: "1px solid #555", padding: 8 }}>
      <div style={{ fontWeight: 700 }}>{title}</div>
      <div style={{ marginTop: 18, borderBottom: "1px solid #555" }} />
    </div>
  );
}

/* =======================
   TABLE COMPONENTS LIST
======================= */
function Th({
  children,
  className = "",
}: {
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <th
      className={["border border-zinc-700 px-3 py-2 font-bold", className].join(
        " "
      )}
    >
      {children}
    </th>
  );
}

function Td({
  children,
  className = "",
  colSpan,
}: {
  children: React.ReactNode;
  className?: string;
  colSpan?: number;
}) {
  return (
    <td
      colSpan={colSpan}
      className={["border border-zinc-700 px-2 py-2", className].join(" ")}
    >
      {children}
    </td>
  );
}
